'use client'
import { useState } from 'react'
import { PROVIDERS_DATA } from '@/lib/data'

const FAQ_ITEMS = [
  { q: "What's the difference between flat-fee and variable pricing?", a: "Flat-fee pricing charges a fixed monthly rate per machine regardless of how much power it uses. Variable (per-kWh) pricing charges based on actual electricity consumption — better for efficient miners, riskier if power costs spike." },
    { q: "What does uptime SLA mean?", a: "Uptime SLA (Service Level Agreement) is a contractual guarantee that your miners will be online a minimum percentage of the time. A 99% SLA means no more than ~7 hours downtime per month. If the host falls below this, you're typically owed credit." },
      { q: "Can I finance my hardware?", a: "Some hosts offer in-house financing or partner with lenders to help you acquire miners. Terms vary — typically 10–15% APR over 24–36 months. Always compare total cost of ownership including interest before committing." },
        { q: "What's the minimum commitment?", a: "Minimum commitments vary widely — some hosts require just 1 month, others lock you in for 12–24 months. Longer commitments often come with better rates. Make sure you understand early termination fees before signing." },
          { q: "How do I know if a host is trustworthy?", a: "Look for verifiable physical locations, published uptime data, transparent pricing, and a track record with other miners. Avoid hosts that won't provide written contracts, ask for large upfront deposits without clear terms, or have no verifiable address." },
            { q: "What's a setup fee?", a: "A setup or configuration fee is a one-time charge when you first deploy your miners at a facility. It covers racking, cabling, and network configuration. Fees typically range from $0–$150 per machine." },
              { q: "Can I move my miners between hosts?", a: "Yes, you own your hardware and can move it. However, most contracts have minimum terms and early termination fees. Shipping miners is also expensive and risky — budget $30–$80/unit for professional packing and freight." },
              ]

              export default function HostsPage() {
                const [openFaq, setOpenFaq] = useState<number | null>(null)

                  return (
                      <main style={{ maxWidth: 1100, margin: '0 auto', padding: '2rem 1rem' }}>
                            <h1 style={{ fontSize: '2rem', fontWeight: 700, marginBottom: '0.5rem' }}>
                                    Bitcoin Mining Hosting Comparison
                                          </h1>
                                                <p style={{ color: '#666', marginBottom: '2rem' }}>
                                                        Compare verified hosting providers. Data sourced directly from operators.
                                                              </p>

                                                                    <div style={{ display: 'grid', gap: '1.5rem', gridTemplateColumns: 'repeat(auto-fill, minmax(320px, 1fr))' }}>
                                                                            {PROVIDERS_DATA.map((p) => (
                                                                                      <div key={p.id} style={{ border: '1px solid #e5e7eb', borderRadius: 12, padding: '1.5rem', background: '#fff' }}>
                                                                                                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '1rem' }}>
                                                                                                                <div>
                                                                                                                                <h2 style={{ fontSize: '1.2rem', fontWeight: 700 }}>{p.name}</h2>
                                                                                                                                                <p style={{ color: '#666', fontSize: '0.875rem' }}>{p.location}</p>
                                                                                                                                                              </div>
                                                                                                                                                                            {p.id === 1 && (
                                                                                                                                                                                            <span style={{ background: '#fbbf24', color: '#000', fontSize: '0.75rem', fontWeight: 700, padding: '2px 8px', borderRadius: 999 }}>
                                                                                                                                                                                                              #1 PICK
                                                                                                                                                                                                                              </span>
                                                                                                                                                                                                                                            )}
                                                                                                                                                                                                                                                        </div>
                                                                                                                                                                                                                                                        
                                                                                                                                                                                                                                                                    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '0.75rem', fontSize: '0.875rem' }}>
                                                                                                                                                                                                                                                                                  <div>
                                                                                                                                                                                                                                                                                                  <div style={{ color: '#888', fontSize: '0.75rem' }}>RATE</div>
                                                                                                                                                                                                                                                                                                                  <div style={{ fontWeight: 600 }}>
                                                                                                                                                                                                                                                                                                                                    {p.pricing_value > 10
                                                                                                                                                                                                                                                                                                                                                        ? `$${p.pricing_value}/mo per miner`
                                                                                                                                                                                                                                                                                                                                                                            : `$${p.pricing_value}/kWh`}
                                                                                                                                                                                                                                                                                                                                                                                            </div>
                                                                                                                                                                                                                                                                                                                                                                                                          </div>
                                                                                                                                                                                                                                                                                                                                                                                                                        <div>
                                                                                                                                                                                                                                                                                                                                                                                                                                        <div style={{ color: '#888', fontSize: '0.75rem' }}>COOLING</div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                        <div style={{ fontWeight: 600 }}>{p.cooling_type}</div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                      </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <div style={{ color: '#888', fontSize: '0.75rem' }}>MIN CONTRACT</div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <div style={{ fontWeight: 600 }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      {p.minimum_commitment_months ? `${p.minimum_commitment_months} months` : 'Contact required'}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <div style={{ color: '#888', fontSize: '0.75rem' }}>UPTIME SLA</div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <div style={{ fontWeight: 600 }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    {p.uptime_sla_percent ? `${p.uptime_sla_percent}%` : 'Contact required'}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <div style={{ color: '#888', fontSize: '0.75rem' }}>POWER</div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <div style={{ fontWeight: 600 }}>{p.power_sources?.join(', ') || 'Contact required'}</div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <div style={{ color: '#888', fontSize: '0.75rem' }}>SETUP FEE</div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <div style={{ fontWeight: 600 }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              {p.setup_fee_usd === 0 ? 'None' : p.setup_fee_usd ? `$${p.setup_fee_usd}` : 'Contact required'}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <div style={{ color: '#888', fontSize: '0.75rem' }}>FINANCING</div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <div style={{ fontWeight: 600 }}>{p.financing_available ? 'Available' : 'No'}</div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <div style={{ color: '#888', fontSize: '0.75rem' }}>AFFILIATE</div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <div style={{ fontWeight: 600 }}>{p.affiliate_program ? 'Yes' : 'No'}</div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <a
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          href={p.website}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        target="_blank"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      rel="noopener noreferrer"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    style={{ display: 'block', marginTop: '1rem', textAlign: 'center', background: '#f59e0b', color: '#000', padding: '0.5rem', borderRadius: 8, fontWeight: 600, fontSize: '0.875rem' }}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                >
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              Visit {p.name} →
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </a>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            ))}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <section style={{ marginTop: '4rem' }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <h2 style={{ fontSize: '1.5rem', fontWeight: 700, marginBottom: '1.5rem' }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          Hosting FAQ
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  </h2>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    {FAQ_ITEMS.map((item, i) => (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <div key={i} style={{ border: '1px solid #e5e7eb', borderRadius: 8, overflow: 'hidden' }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <button
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              onClick={() => setOpenFaq(openFaq === i ? null : i)}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              style={{ width: '100%', textAlign: 'left', padding: '1rem 1.25rem', background: '#f9fafb', border: 'none', cursor: 'pointer', fontWeight: 600, fontSize: '0.95rem', display: 'flex', justifyContent: 'space-between' }}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            >
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            {item.q}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <span>{openFaq === i ? '−' : '+'}</span>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </button>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        {openFaq === i && (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <div style={{ padding: '1rem 1.25rem', background: '#fff', color: '#555', lineHeight: 1.6 }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          {item.a}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        )}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              ))}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </section>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                </main>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  )
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  }
